using System;using System.Collections.Generic;using System.Linq;class A{static int W,H;static int Nodes(char[,]g){int c=0;for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(g[y,x]=='@')c++;return c;}static int Boom(char[,]g,int bx,int by,char[,]ng){for(int y=0;y<H;y++)for(int x=0;x<W;x++)ng[y,x]=g[y,x];int h=0;if(ng[by,bx]=='@'){ng[by,bx]='.';h++;}int[]dx={1,-1,0,0},dy={0,0,1,-1};for(int d=0;d<4;d++)for(int i=1;i<=3;i++){int x=bx+dx[d]*i,y=by+dy[d]*i;if(x<0||x>=W||y<0||y>=H||ng[y,x]=='#')break;if(ng[y,x]=='@'){ng[y,x]='.';h++;}}return h;}static List<(int,int)>plan=new();static bool Solve(char[,]g,int b,int t){if(Nodes(g)==0)return true;if(b==0||t<3)return false;var cs=new List<(int s,int x,int y)>();for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(g[y,x]!='#'&&g[y,x]!='@'){var ng=new char[H,W];int s=Boom(g,x,y,ng);if(s>0)cs.Add((-s,x,y));}cs.Sort();foreach(var(_,cx,cy)in cs.Take(50)){var ng=new char[H,W];Boom(g,cx,cy,ng);plan.Add((cx,cy));if(Solve(ng,b-1,t-3))return true;plan.RemoveAt(plan.Count-1);}return false;}static void Main(){var p=Console.ReadLine().Split(' ');W=int.Parse(p[0]);H=int.Parse(p[1]);var G=new char[H,W];for(int y=0;y<H;y++){var r=Console.ReadLine();for(int x=0;x<W;x++)G[y,x]=r[x];}int pi=0;for(;;){p=Console.ReadLine().Split(' ');int t=int.Parse(p[0]),b=int.Parse(p[1]);if(pi>=plan.Count)Solve(G,b,t);if(pi<plan.Count){var(x,y)=plan[pi++];Console.WriteLine($"{x} {y}");for(int i=0;i<2;i++){Console.ReadLine();Console.WriteLine("WAIT");}}else Console.WriteLine("WAIT");}}}